class Solution {
public:
    long long mostPoints(vector<vector<int>>& questions) {
        int n = questions.size();
        vector<long long> dp(n + 1, 0);
        for (int i = n - 1; i >= 0; --i) {
            int points = questions[i][0];
            int brainpower = questions[i][1];
            int next_i = min(i + brainpower + 1, n);
            dp[i] = max(dp[i + 1], points + dp[next_i]);
        }
        return dp[0];
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
energy implications: LOW
explanation: Dynamic programming is used to track the maximum points that can be earned from the current question to the end. The dp array is filled in reverse order, considering whether to solve or skip each question. The maximum points are then returned from the first question. 
